/**
 * Approval Queue Page
 * Admin approves/rejects room booking requests
 */

import React, { useState, useEffect } from 'react';
import { getBookingRequests, approveBooking, rejectBooking } from '../../services/admin_service';
import StatusBadge from '../../components/common/StatusBadge';
import LoadingSpinner from '../../components/common/LoadingSpinner';
import ConfirmModal from '../../components/common/ConfirmModal';

const ApprovalQueue = () => {
    const [requests, setRequests] = useState([]);
    const [loading, setLoading] = useState(true);
    const [activeTab, setActiveTab] = useState('pending');
    const [selectedRequest, setSelectedRequest] = useState(null);
    const [showApproveModal, setShowApproveModal] = useState(false);
    const [showRejectModal, setShowRejectModal] = useState(false);
    const [error, setError] = useState('');

    useEffect(() => {
        fetchRequests();
    }, []);

    const fetchRequests = async () => {
        setLoading(true);
        const result = await getBookingRequests();
        if (result.success) {
            setRequests(result.data || []);
        } else {
            setError(result.message);
        }
        setLoading(false);
    };

    const handleApprove = async () => {
        if (!selectedRequest) return;

        const result = await approveBooking(selectedRequest.booking_id);
        if (result.success) {
            setShowApproveModal(false);
            setSelectedRequest(null);
            fetchRequests();
        } else {
            setError(result.message);
        }
    };

    const handleReject = async () => {
        if (!selectedRequest) return;

        const result = await rejectBooking(selectedRequest.booking_id);
        if (result.success) {
            setShowRejectModal(false);
            setSelectedRequest(null);
            fetchRequests();
        } else {
            setError(result.message);
        }
    };

    const getFilteredRequests = () => {
        if (activeTab === 'all') return requests;
        return requests.filter(req => req.status?.toLowerCase() === activeTab);
    };

    const getStatusCount = (status) => {
        if (status === 'all') return requests.length;
        return requests.filter(req => req.status?.toLowerCase() === status).length;
    };

    const filteredRequests = getFilteredRequests();

    if (loading) return <LoadingSpinner />;

    return (
        <div className="page-container">
            <div className="page-header">
                <h1>Approval Queue</h1>
                <p>Review and manage room booking requests</p>
            </div>

            {error && <div className="error-message">{error}</div>}

            <div className="approval-tabs">
                <button
                    className={`tab-btn ${activeTab === 'all' ? 'active' : ''}`}
                    onClick={() => setActiveTab('all')}
                >
                    All ({getStatusCount('all')})
                </button>
                <button
                    className={`tab-btn ${activeTab === 'pending' ? 'active' : ''}`}
                    onClick={() => setActiveTab('pending')}
                >
                    Pending ({getStatusCount('pending')})
                </button>
                <button
                    className={`tab-btn ${activeTab === 'approved' ? 'active' : ''}`}
                    onClick={() => setActiveTab('approved')}
                >
                    Approved ({getStatusCount('approved')})
                </button>
                <button
                    className={`tab-btn ${activeTab === 'rejected' ? 'active' : ''}`}
                    onClick={() => setActiveTab('rejected')}
                >
                    Rejected ({getStatusCount('rejected')})
                </button>
            </div>

            <div className="approval-list">
                {filteredRequests.map((request) => (
                    <div key={request.booking_id} className={`approval-card ${request.status?.toLowerCase()}`}>
                        <div className="approval-header">
                            <div>
                                <h3>{request.Teacher?.name || `Request #${request.booking_id}`}</h3>
                                <StatusBadge status={request.status || 'Pending'} size="sm" />
                            </div>
                            {request.status?.toLowerCase() === 'pending' && (
                                <div className="approval-actions">
                                    <button
                                        className="btn-primary"
                                        style={{ background: 'var(--success)' }}
                                        onClick={() => {
                                            setSelectedRequest(request);
                                            setShowApproveModal(true);
                                        }}
                                    >
                                        ✓ Approve
                                    </button>
                                    <button
                                        className="btn-danger"
                                        onClick={() => {
                                            setSelectedRequest(request);
                                            setShowRejectModal(true);
                                        }}
                                    >
                                        ✗ Decline
                                    </button>
                                </div>
                            )}
                        </div>
                        <div className="approval-details">
                            <div className="detail-item">
                                <span className="detail-label">Room</span>
                                <span className="detail-value">{request.Room?.room_number || 'N/A'}</span>
                            </div>
                            <div className="detail-item">
                                <span className="detail-label">Purpose</span>
                                <span className="detail-value">{request.purpose || 'Not specified'}</span>
                            </div>
                            <div className="detail-item">
                                <span className="detail-label">Date</span>
                                <span className="detail-value">
                                    {request.booking_date ? new Date(request.booking_date).toLocaleDateString() : 'N/A'}
                                </span>
                            </div>
                            <div className="detail-item">
                                <span className="detail-label">Time</span>
                                <span className="detail-value">
                                    {request.TimeSlot?.start_time && request.TimeSlot?.end_time
                                        ? `${request.TimeSlot.start_time} - ${request.TimeSlot.end_time}`
                                        : 'Not specified'}
                                </span>
                            </div>
                        </div>
                    </div>
                ))}

                {filteredRequests.length === 0 && (
                    <div className="empty-state">No {activeTab} requests found</div>
                )}
            </div>

            {/* Approve Modal */}
            <ConfirmModal
                isOpen={showApproveModal}
                onClose={() => setShowApproveModal(false)}
                onConfirm={handleApprove}
                title="Approve Booking"
                message={`Are you sure you want to approve this booking request for ${selectedRequest?.Room?.room_number}?`}
                confirmText="Approve"
                confirmVariant="primary"
            />

            {/* Reject Modal */}
            <ConfirmModal
                isOpen={showRejectModal}
                onClose={() => setShowRejectModal(false)}
                onConfirm={handleReject}
                title="Reject Booking"
                message={`Are you sure you want to reject this booking request for ${selectedRequest?.Room?.room_number}?`}
                confirmText="Reject"
                confirmVariant="danger"
            />
        </div>
    );
};

export default ApprovalQueue;
